toolArgs.file_text:
@page "/book-appointment"
@rendermode InteractiveServer
@using sv_ca5f0c4624ff4ea4b697ea18b1c3f09e.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

@* ───── STEP 1 ───── *@
<h2>Step 1 — Patient Information</h2>

<EditForm EditContext="step1Context" OnValidSubmit="HandleStep1Valid" FormName="step1">
    <DataAnnotationsValidator />
    <CustomValidator @ref="step1Validator" />

    <div>
        <label>
            Patient Name:
            <InputText @bind-Value="step1.PatientName" />
            <ValidationMessage For="() => step1.PatientName" />
        </label>
    </div>

    <div>
        <label>
            Email:
            <InputText @bind-Value="step1.Email" />
            <ValidationMessage For="() => step1.Email" />
        </label>
    </div>

    <div>
        <label>
            Phone:
            <InputText @bind-Value="step1.Phone" />
            <ValidationMessage For="() => step1.Phone" />
        </label>
    </div>

    <div>
        <label>
            Insurance Provider:
            <InputSelect @bind-Value="step1.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => step1.InsuranceProvider" />
        </label>
    </div>

    <button type="submit">Next</button>
</EditForm>

@* ───── STEP 2 ───── *@
@if (showStep2)
{
    <h2>Step 2 — Appointment Details</h2>

    <EditForm EditContext="step2Context" OnSubmit="HandleStep2Submit" FormName="step2">
        <DataAnnotationsValidator />
        <CustomValidator @ref="step2Validator" />

        <div>
            <label>
                Preferred Doctor:
                <InputSelect @bind-Value="step2.Doctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => step2.Doctor" />
            </label>
        </div>

        <div>
            <label>
                Date:
                <InputDate @bind-Value="step2.AppointmentDate" @bind:after="OnDateChanged" />
                <ValidationMessage For="() => step2.AppointmentDate" />
            </label>
        </div>

        <div>
            <label>
                Time Slot:
                <InputSelect @bind-Value="step2.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => step2.TimeSlot" />
            </label>
        </div>

        <div>
            <label>
                Reason for Visit:
                <InputTextArea @bind-Value="step2.Reason" />
                <ValidationMessage For="() => step2.Reason" />
            </label>
        </div>

        <button type="submit" disabled="@isSubmitting">
            @(isSubmitting ? "Checking..." : "Check Availability")
        </button>
    </EditForm>

    @if (isBooked)
    {
        <p><strong>Appointment booked successfully!</strong></p>
    }
}

@code {
    // Step 1
    private Step1Model step1 = new();
    private EditContext step1Context = default!;
    private CustomValidator? step1Validator;

    // Step 2
    private Step2Model step2 = new();
    private EditContext step2Context = default!;
    private CustomValidator? step2Validator;

    private bool showStep2;
    private bool isSubmitting;
    private bool isBooked;

    private List<string> doctors = new();
    private List<string> availableSlots = new();

    protected override void OnInitialized()
    {
        step1Context = new EditContext(step1);
        step2Context = new EditContext(step2);
    }

    private async Task HandleStep1Valid()
    {
        doctors = await AppointmentSvc.GetDoctorsAsync();
        showStep2 = true;
    }

    private async Task OnDateChanged()
    {
        if (!string.IsNullOrEmpty(step2.Doctor) && step2.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                step2.Doctor, step2.AppointmentDate.Value);
        }
    }

    private async Task HandleStep2Submit()
    {
        step2Validator!.ClearErrors();

        // Client-side validation first
        if (!step2Context.Validate())
            return;

        // Future-date check
        if (step2.AppointmentDate.HasValue
            && step2.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            step2Validator.DisplayErrors(new Dictionary<string, List<string>>
            {
                [nameof(Step2Model.AppointmentDate)] = ["Date must be in the future."]
            });
            return;
        }

        isSubmitting = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                step1.Email!,
                step1.InsuranceProvider!,
                step2.Doctor!,
                step2.TimeSlot!);

            if (errors.Count > 0)
            {
                // Map Email/InsuranceProvider errors to step1, rest to step2
                var step1Errors = new Dictionary<string, List<string>>();
                var step2Errors = new Dictionary<string, List<string>>();

                foreach (var (field, messages) in errors)
                {
                    if (field is nameof(BookAppointmentModel.Email))
                    {
                        step1Validator!.DisplayErrors(
                            new Dictionary<string, List<string>> { [field] = messages });
                    }
                    else
                    {
                        step2Errors[field] = messages;
                    }
                }

                if (step2Errors.Count > 0)
                    step2Validator.DisplayErrors(step2Errors);

                return;
            }

            await AppointmentSvc.BookAppointmentAsync(new BookAppointmentModel
            {
                PatientName = step1.PatientName,
                Email = step1.Email,
                Phone = step1.Phone,
                InsuranceProvider = step1.InsuranceProvider,
                Doctor = step2.Doctor,
                AppointmentDate = step2.AppointmentDate,
                TimeSlot = step2.TimeSlot,
                Reason = step2.Reason
            });

            isBooked = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

